class Solution:
    def combine(self, n: int, k: int) -> List[List[int]]:
        result: List[List[int]] = []

        def dfs(start, comb):
            if len(comb) == k:
                result.append(comb[:])
                return
            for i in range(start, n + 1):
                comb.append(i)
                dfs(i + 1, comb)
                comb.pop()

        dfs(1, [])

        return result
